function Sidebar({ chats, activeChatId, onNewChat, onSelectChat }) {
    return (
        <div
            style={{
                width: "280px",
                backgroundColor: "#0f172a",
                color: "#e5e7eb",
                display: "flex",
                flexDirection: "column",
            }}
        >
            <div style={{ padding: "16px", fontSize: "18px", fontWeight: "600" }}>
                AI Chat
            </div>

            <button
                onClick={onNewChat}
                style={{
                    margin: "0 16px 16px",
                    padding: "12px",
                    borderRadius: "10px",
                    backgroundColor: "#2563eb",
                    color: "white",
                    border: "none",
                    fontSize: "15px",
                    cursor: "pointer",
                }}
            >
                + New Chat
            </button>

            <div style={{ flex: 1, overflowY: "auto" }}>
                {chats.map((chat) => (
                    <div
                        key={chat.id}
                        onClick={() => onSelectChat(chat.id)}
                        style={{
                            margin: "4px 8px",
                            padding: "12px",
                            borderRadius: "10px",
                            cursor: "pointer",
                            backgroundColor:
                                chat.id === activeChatId ? "#1e293b" : "transparent",
                        }}
                    >
                        {chat.title || "New conversation"}
                    </div>
                ))}
            </div>
        </div>
    );
}

export default Sidebar;
